parameters.jsCode:
// Parse the Claude response, fall back to safe defaults, and merge with the intake fields
const intake = $('Set Intake Fields').item.json;
const raw = $json.content?.[0]?.text || '{}';

let parsed = {
  customer_email_message: '',
  customer_sms_message: '',
  internal_summary: '',
  request_category: '',
  priority: 'normal',
  missing_info: []
};

try {
  const cleaned = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed.internal_summary = 'AI returned malformed JSON: ' + raw.slice(0, 200);
}

let emailMsg = (parsed.customer_email_message || '').toString().trim();
if (!emailMsg) {
  emailMsg = 'Hi ' + intake.fullName + ', thanks for your request. We have received it and our team will follow up shortly. Your reference is ' + intake.caseRef + '. - ' + intake.businessName;
}

let smsMsg = (parsed.customer_sms_message || '').toString().trim();
if (!smsMsg) {
  smsMsg = 'Hi ' + intake.fullName + ', we got your request (' + intake.caseRef + '). Our team will be in touch soon. - ' + intake.businessName;
}
if (smsMsg.length > 320) { smsMsg = smsMsg.slice(0, 317) + '...'; }

const missingInfo = Array.isArray(parsed.missing_info) ? parsed.missing_info.join(' | ') : '';
const priority = ['high', 'normal', 'low'].includes(parsed.priority) ? parsed.priority : 'normal';

return [{
  json: {
    ...intake,
    customer_email_message: emailMsg,
    customer_sms_message: smsMsg,
    internal_summary: parsed.internal_summary || '',
    request_category: parsed.request_category || intake.requestType,
    priority: priority,
    missing_info: missingInfo
  }
}];
